const item = $input.first().json;

if (item.error) {
  const status = item.error.status;

  let error_message;
  if (status === 401) {
    error_message = "API Key inválida.";
  } else if (status === 404) {
    error_message = "Cidade não encontrada.";
  } else {
    error_message = `Erro inesperado (${status}).`;
  }

  return [{
    json: {
      success: false,
      error_code: status,
      error_message
    }
  }];
}

function getEmoji(id) {
  const numId = Number(id);

  if (numId >= 200 && numId < 300) return "⛈️";
  if (numId >= 300 && numId < 400) return "🌦️";
  if (numId >= 500 && numId < 600) return numId === 511 ? "🌨️" : "🌧️";
  if (numId >= 600 && numId < 700) return numId >= 611 && numId <= 616 ? "🌨️" : "❄️";
  if (numId >= 700 && numId < 800) {
    const atmo = new Map([
      [701, "🌫️"], [711, "💨"], [721, "🌁"], [731, "🌪️"],
      [741, "🌫️"], [751, "🌪️"], [761, "🌪️"], [762, "🌋"],
      [771, "💨"],  [781, "🌪️"]
    ]);
    return atmo.has(numId) ? atmo.get(numId) : "🌫️";
  }
  const clear = new Map([
    [800, "☀️"], [801, "🌤️"], [802, "⛅"], [803, "🌥️"], [804, "☁️"]
  ]);
  return clear.has(numId) ? clear.get(numId) : "🌡️";
}

const weatherId = item.weather[0].id;

return [{
  json: {
    success: true,
    city: item.name,
    country: item.sys.country,
    temp: Math.round(item.main.temp),
    feels_like: Math.round(item.main.feels_like),
    description: item.weather[0].description,
    emoji: getEmoji(weatherId),
    humidity: item.main.humidity,
    wind_speed: Math.round(item.wind.speed * 3.6)
  }
}];

