const llmItem = $input.first().json;
const weatherItem = $('Normalize').first().json;
const nextYear = new Date().getFullYear() + 1;

const capitalize = (str) => str.charAt(0).toUpperCase() + str.slice(1);

// LLM funcionou — extrai JSON
if (llmItem.text) {
  try {
    const cleaned = llmItem.text.replace(/```json|```/g, '').trim();
    const parsed = JSON.parse(cleaned);
    return [{
      json: {
        ...weatherItem,
        message: `${weatherItem.emoji} *${weatherItem.city}, ${weatherItem.country}*\n${capitalize(weatherItem.description)}\n\n🌡️ ${weatherItem.temp}°C • sensação ${weatherItem.feels_like}°C\n💧 Umidade: ${weatherItem.humidity}%\n💨 Vento: ${weatherItem.wind_speed} km/h\n\n${parsed.message}`
      }
    }];
  } catch(e) {}
}

// Fallback — usa dados do Normalize
const { temp, humidity, wind_speed, city, country, emoji, description, feels_like } = weatherItem;

let laundry;
if (humidity >= 90) {
  laundry = `Lavar roupa hoje? Vai secar em ${nextYear}. 💀`;
} else if (humidity >= 70) {
  laundry = "Pode lavar, mas vai torcer na mão mesmo — o sol não vai ajudar.";
} else if (wind_speed > 30) {
  laundry = "Ótimo dia pra lavar! Só não estende na janela ou vai ter lingerie voando pelo bairro. 🌪️";
} else if (temp > 25 && humidity < 60) {
  laundry = "Dia perfeito! Lava roupa, estende e já seca antes do almoço. 👕☀️";
} else {
  laundry = "Dia razoável. Lava roupa se quiser, mas sem pressa.";
}

return [{
  json: {
    ...weatherItem,
    message: `${emoji} *${city}, ${country}*\n${capitalize(description)}\n\n🌡️ ${temp}°C • sensação ${feels_like}°C\n💧 Umidade: ${humidity}%\n💨 Vento: ${wind_speed} km/h\n\n${laundry}`
  }
}];
